+#[test]
+fn fopen_mode_wplus_truncates_and_readwrite() {
+    let path = temp_path("fopen_mode_wplus");
+    fs::write(&path, b"old").unwrap();
+    let path_c = path_cstring(&path);
+
+    let stream = unsafe { fopen(path_c.as_ptr(), c"w+".as_ptr()) };
