+
+    // Write
+    let written = unsafe { fputs(c"new".as_ptr(), stream) };
+    assert!(written >= 0);
+
+    // Seek back and read
+    unsafe { rewind(stream) };
+    let mut buf = [0u8; 4];
+    let n = unsafe { fread(buf.as_mut_ptr().cast(), 1, 3, stream) };
+    assert_eq!(n, 3);
+    assert_eq!(&buf[..3], b"new");
+
+    unsafe { fclose(stream) };
+    let _ = fs::remove_file(path);
+}
