+    let stream = unsafe { fopen(path_c.as_ptr(), c"we".as_ptr()) };
+    assert!(!stream.is_null(), "fopen(we) should succeed");
+
+    let fd = unsafe { fileno(stream) };
+    assert!(fd >= 0);
+
+    // Check FD_CLOEXEC flag
+    let flags = unsafe { libc::fcntl(fd, libc::F_GETFD) };
+    assert!(flags >= 0);
